    // Create reactive variables and calculations
    auto varA = var(valueA).setName("input_a");
    auto varB = var(valueB).setName("input_b");

    auto sumCalc = calc([](int a, int b) {
        return a + b;
    }, varA, varB).setName("sum_calc");

